import{_ as t,o,c as n,ag as p}from"./chunks/framework.CAXxHpAX.js";const b=JSON.parse('{"title":"江南地区开发的原因：南方战乱较少，社会比","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-5.md","filePath":"notes/note-5.md"}'),e={name:"notes/note-5.md"};function r(s,a,l,c,d,i){return o(),n("div",null,[...a[0]||(a[0]=[p('<h1 id="江南地区开发的原因-南方战乱较少-社会比" tabindex="-1">江南地区开发的原因：南方战乱较少，社会比 <a class="header-anchor" href="#江南地区开发的原因-南方战乱较少-社会比" aria-label="Permalink to &quot;江南地区开发的原因：南方战乱较少，社会比&quot;">​</a></h1><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">江南地区开发的原因：</span>南方战乱较少，社会比较安定，统治者的政策支持；北人南迁，带来了劳动力、先进的生产工具和生产技术（根因）；南方自然条件优越。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">江南地区开发的影响：</span>为我国古代经济重心的南移奠基。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">魏晋时期人口迁徙：</span>少数民族内迁（五胡内迁）；汉族人迁往江南（人口南迁）。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">北方民族交融的表现：</span>胡汉观念逐渐淡薄，民族隔阂与偏见减少。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">祖冲之：</span>南北朝，把圆周率精确到小数点后第七位，领先世界近千年。《大明历》《缀术》</p><p>锺繇独创楷书书法</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">《齐民要术》的原则：</span>民生为本；农业生产遵循自然规律；农作物种植因地制宜、不误农时。</p><p>东晋、王羲之，书圣，《兰亭集序》，天下第一行书。</p><p>东晋、顾恺之《女史箴图》《洛神赋图》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">山西大同云冈石窟、河南洛阳龙门石窟：</span>佛教主题</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">秦汉的朝代特征：</span>统一多民族国家的建立和巩固 魏晋朝代特征：政权分立与民族交融</p>',12)])])}const v=t(e,[["render",r]]);export{b as __pageData,v as default};
